/**
 * Manages execution of registered processors for each lifecycle stage.
 * Plugins and core modules can register processors dynamically.
 * Erweiterung: Annotation-Prozessoren mit stage-spezifischen Methoden
 */

const stageProcessors = new Map();

/**
 * Registers a processor function for a specific stage.
 *
 * @param {string} stage - The name of the stage (e.g. 'Scan', 'DI', 'Init').
 * @param {Function} fn - The processor function to execute during the stage.
 */
function registerStageProcessor(stage, fn) {
  if (!stageProcessors.has(stage)) {
    stageProcessors.set(stage, []);
  }
  stageProcessors.get(stage).push(fn);
}

/**
 * Executes all registered processors for a given stage.
 * Each processor receives the shared context object.
 * Automatically initializes context.log as an array if missing.
 * Zusätzlich: Führt Annotation-Prozessoren mit passender process<Stage>-Methode aus.
 *
 * @param {string} stage - The stage to execute.
 * @param {Object} context - The shared context passed to each processor.
 * @returns {Promise<void>}
 */
async function executeStage(stage, context) {
  if (!context) context = {};
  if (!Array.isArray(context.log)) context.log = [];

  // 1. Ausführung der registrierten Stage-Prozessoren
  const processors = stageProcessors.get(stage) || [];
  for (const processor of processors) {
    await processor(context);
  }

  // 2. Ausführung der Annotation-Prozessoren mit process<Stage>-Methoden
  const fnName = `process${stage}`;
  const annotations = context.annotations || [];

  if (stage === 'DI') {
    // First pass: process DI for all components (no propertyName)
    for (const { processor, meta } of annotations) {
      if (!meta.propertyName && typeof processor?.[fnName] === 'function') {
        await processor[fnName](meta, context);
        // Ensure all component instances are registered in DI container
        if (meta.className && meta.instance && context.container && typeof context.container.register === 'function') {
          context.container.register(meta.className, meta.instance);
        }
        context.log.push(`[DI DEBUG] Component DI: ${meta.className} instance keys: ${meta.instance ? Object.keys(meta.instance) : 'undefined'}`);
        context.log.push(`Annotation ${meta.name} processed in stage ${stage}`);
      }
    }
    // Second pass: process DI for all property-level qualifiers
    for (const { processor, meta } of annotations) {
      if (meta.propertyName && typeof processor?.[fnName] === 'function') {
        // Ensure parent instance is registered before property-level DI
        if (meta.className && !meta.instance && context.container && typeof context.container.resolve === 'function') {
          try {
            meta.instance = context.container.resolve(meta.className);
          } catch (e) {}
        }
        await processor[fnName](meta, context);
        context.log.push(`[DI DEBUG] Qualifier DI: ${meta.className}.${meta.propertyName} = ${meta.instance ? typeof meta.instance[meta.propertyName] : 'undefined'}`);
        context.log.push(`Annotation ${meta.name} processed in stage ${stage}`);
      }
    }
  } else {
    for (const { processor, meta } of annotations) {
      if (typeof processor?.[fnName] === 'function') {
        await processor[fnName](meta, context);
        context.log.push(`Annotation ${meta.name} processed in stage ${stage}`);
      }
    }
  }

  // Fallback: Sicherstellen, dass context.log existiert
  if (!Array.isArray(context.log)) {
    context.log = [];
  }
}

/**
 * Returns all registered processors for a given stage.
 * Useful for debugging or introspection.
 *
 * @param {string} stage
 * @returns {Function[]}
 */
function getStageProcessors(stage) {
  return stageProcessors.get(stage) || [];
}

module.exports = {
  registerStageProcessor,
  executeStage,
  getStageProcessors
};